/**
 * Labeled fixture corpus for the AI-attribution benchmark harness
 * (see `aiAttributionBenchmark.ts` and `__tests__/lib/aiAttributionBenchmark.test.ts`).
 *
 * HUMAN samples are verbatim excerpts from real, well-known open-source
 * libraries (zod, DOMPurify, entities) that predate widespread LLM-assisted
 * coding and were written/reviewed by human maintainers.
 *
 * AI samples were freshly generated by Claude (this assistant) for this
 * benchmark, in typical LLM-assistant style: heavy per-function JSDoc,
 * uniform try/catch with console.error, `{ success, data, error }` result
 * shapes, defensive null checks, and generic naming.
 *
 * This is a small (n=10), TS/JS-only internal benchmark — not a substitute
 * for a large labeled corpus, but it gives concrete precision/recall/F1/AUC
 * numbers instead of none.
 */

export type BenchmarkLabel = "human" | "ai";

export interface BenchmarkSample {
  id:       string;
  label:    BenchmarkLabel;
  language: string;
  source:   string;  // provenance note
  content:  string;
}

